    buttons: btns,
    movementX: 0, movementY: 0,
    width: 1, height: 1,
    pressure: 0.5, tiltX: 0, tiltY: 0, twist: 0
  });

  // Full sequence: move → down → (wait) → up
  canvas.dispatchEvent(new PointerEvent('pointermove', makeOpts('pointermove', cx, cy, 0)));
  canvas.dispatchEvent(new PointerEvent('pointerdown', makeOpts('pointerdown', cx, cy, 1)));

  setTimeout(() => {
    canvas.dispatchEvent(new PointerEvent('pointerup', makeOpts('pointerup', cx, cy, 0)));
  }, 50);

  return 'Dispatched full sequence at ' + cx + ',' + cy;
})()

