  // Check for R3F internal store reference
  const keys = Object.keys(canvas).filter(k => k.startsWith('__') || k.includes('r3f') || k.includes('fiber') || k.includes('store'));

  // Check parent div for R3F store
  const parent = canvas.parentElement;
  const parentKeys = Object.keys(parent).filter(k => k.startsWith('__') || k.includes('r3f') || k.includes('fiber') || k.includes('store'));

  // Try to find the R3F root store
  const container = canvas.closest('.canvas-container');
  const containerKeys = container ? Object.keys(container).filter(k => k.startsWith('__') || k.includes('r3f')) : [];

  return JSON.stringify({
    canvasKeys: keys,
    parentKeys: parentKeys,
    containerKeys: containerKeys,
    canvasParentTag: parent?.tagName,
    containerTag: container?.tagName
  }, null, 2);
})()

