  // Move to near bead 1 position (screen y ~227, so around 230)
  const x = 640, y = 230;

  const moveOpts = {
    clientX: x, clientY: y, offsetX: x, offsetY: y,
    layerX: x, layerY: y, pageX: x, pageY: y,
    screenX: x, screenY: y,
    bubbles: true, cancelable: true, composed: true,
    pointerId: 1, pointerType: 'mouse', isPrimary: true,
    button: 0, buttons: 0, movementX: 0, movementY: 0,
    width: 1, height: 1, pressure: 0.5
  };

  // Move first
  canvas.dispatchEvent(new PointerEvent('pointermove', moveOpts));

  // Small delay, then click
  setTimeout(() => {
    canvas.dispatchEvent(new PointerEvent('pointerdown', { ...moveOpts, buttons: 1 }));
    setTimeout(() => {
      canvas.dispatchEvent(new PointerEvent('pointerup', moveOpts));
    }, 80);
  }, 50);

  return 'Dispatched move + click at ' + x + ',' + y;
})()

