(() => {
  // Simulate a drag: pointerdown at bead position, move, then pointerup
  const canvas = document.querySelector('canvas[data-engine]');
  const x = 640, y = 120;

  const opts = (ox, oy, btns) => ({
    clientX: ox, clientY: oy, offsetX: ox, offsetY: oy,
    layerX: ox, layerY: oy, pageX: ox, pageY: oy, screenX: ox, screenY: oy,
    bubbles: true, cancelable: true, composed: true,
    pointerId: 1, pointerType: 'mouse', isPrimary: true,
    button: 0, buttons: btns, width: 1, height: 1, pressure: 0.5
  });

  // Move to bead position
  canvas.dispatchEvent(new PointerEvent('pointermove', opts(x, y, 0)));

  // Press down
  canvas.dispatchEvent(new PointerEvent('pointerdown', opts(x, y, 1)));

  // Wait 300ms (exceeds TAP_MAX_DURATION of 200ms) and move significantly
  setTimeout(() => {
    const newX = x + 60;
    const newY = y + 30;
    canvas.dispatchEvent(new PointerEvent('pointermove', opts(newX, newY, 1)));
  }, 300);

  // Release after moving
  setTimeout(() => {
    const newX = x + 60;
    const newY = y + 30;
    canvas.dispatchEvent(new PointerEvent('pointerup', opts(newX, newY, 0)));
  }, 400);

  return 'Drag simulation dispatched';
})()

